/**
 * 该文件由 scripts/syncPrompts.ts 自动生成，请勿手动修改。
 * 包含 Base64 编码后的提示词内容，用于生产环境下从内存直接读取。
 */
export const PROMPTS_BASE64: Record<string, string> = {
    "beforePlanning": "",
    "inspector": "",
    "plan_setStep": "",
    "planner": "",
    "restorer": "",
    "run_main": "",
    "run_tools": ""
};

/** 解码后的提示词缓存 */
const decodedCache: Record<string, string> = {};

/** 获取解码后的提示词 */
export function getGeneratedPrompt(key: string): string {
    if (decodedCache[key]) return decodedCache[key];
    const base64Content = PROMPTS_BASE64[key];
    if (base64Content) {
        decodedCache[key] = Buffer.from(base64Content, 'base64').toString('utf-8');
        return decodedCache[key];
    }
    return '';
}
